```plantuml
@startuml
title Diagrama de Classe - Acompanhamentos

abstract class Acai {
  # String descricao
  # Tamanho tamanho
  + {abstract} double getPreco()
  + String getDescricao()
  + Tamanho getTamanho()
}

note left of Acai::getPreco
  Método abstrato que deve ser
  implmentado por toda Classe
  que herda de Acai
end note

enum Tamanho {
  PEQUENO
  MEDIO
  GRANDE
}

class Morango {
  - double preco
  - double preco
  + double getPreo()
  + double getPreco()
}

class LeiteEmPo {
  - double preco
  + double getPreco()
}

class AcaiNaBarca {
}

class AcaiNaTigela {
}

class AcaiNoCopo {
}

class AcaiNaBarcaComMorango {
  - AcaiNaBarca acaiNaBarca
  - Morango morango
}

class AcaiNaTigelaComMorango {
  - AcaiNaTigela AcaiNaTigela
  - Morango morango
}

class AcaiNoCopoComMorango {
  - AcaiNoCopo AcaiNoCopo
  - Morango morango
}

class AcaiNaBarcaComMorangoELeiteEmPo {
  - AcaiNaBarca acaiNaBarca
  - Morango morango
  - LeiteEmPo leiteEmPo
}

Acai <|-- AcaiNaBarca
Acai <|-- AcaiNaTigela
Acai <|-- AcaiNoCopo
Acai <|-- AcaiNaBarcaComMorango
Acai <|-- AcaiNaTigelaComMorango
Acai <|-- AcaiNoCopoComMorango
Acai <|-- AcaiNaBarcaComMorangoELeiteEmPo

@enduml
```
